import { experimental_streamedQuery as streamedQuery, createQuery, queryOptions as createQueryOptions, } from '@tanstack/svelte-query';
import { useQueryLogger } from '../query-logger';
import { useEnabledQueries } from './use-enabled-queries.svelte';
export const streamQueryKey = (partID, name, methodName, args) => [
    'viam-svelte-sdk',
    'partID',
    partID,
    'resource',
    name,
    methodName,
    ...(args ? [args] : []),
];
export const createResourceStream = (client, method, ...additional) => {
    const debug = useQueryLogger();
    const enabledQueries = useEnabledQueries();
    let [args, options] = additional;
    if (options === undefined && args !== undefined) {
        options = args;
        args = undefined;
    }
    const _options = $derived(typeof options === 'function' ? options() : options);
    const _args = $derived(typeof args === 'function' ? args() : args);
    const name = $derived(client.current?.name);
    const methodName = $derived(String(method));
    const refetchMode = $derived(_options?.refetchMode ?? 'reset');
    const partID = $derived(client.current?.partID);
    const queryKey = $derived(streamQueryKey(partID, name, methodName, _args));
    function processStream() {
        const clientFunc = client.current?.[method];
        if (typeof clientFunc !== 'function') {
            throw new TypeError(`${String(method)} is not a method on the resource client.`);
        }
        const logger = debug.createLogger();
        logger('REQ', name, methodName, _args);
        try {
            const response = clientFunc?.apply(client.current, _args);
            console.log('response', typeof response);
            logger('RES', name, methodName, response);
            return response;
        }
        catch (error) {
            logger('ERR', name, methodName, error);
            throw error;
        }
    }
    const queryOptions = $derived(createQueryOptions({
        queryKey,
        enabled: client.current !== undefined &&
            _options?.enabled !== false &&
            enabledQueries.resourceQueries,
        queryFn: streamedQuery({
            streamFn: processStream,
            refetchMode,
        }),
    }));
    return createQuery(() => queryOptions);
};
